        });

        node.warn('🤖 자동화 실행: ' + rule.name + ' → ' + actions.map(function(a) {
            var ds = a.duration ? ' (' + Math.floor(a.duration/60) + '분' + (a.duration%60) + '초)' : '';
            return a.deviceId + ' ' + a.command + ds;
        }).join(', '));
    }
}

if (actionsToExecute.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: rules.length + '개 규칙 평가, 실행 없음' });
    if (updateMessages.length === 0) return null;
}

node.status({ fill: 'green', shape: 'dot', text: '실행: ' + actionsToExecute.length + '개 동작' });

// ── 제어 메시지 생성 ──
var controlMessages = actionsToExecute.map(function(action) {
    return {
        control: {
            houseId: action.houseId,
            deviceId: action.deviceId,
            deviceType: action.deviceType,
            command: action.command,
            operator: 'automation',
            requestId: 'auto_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4),
            timestamp: now.toISOString()
        },
        _action: action
    };
});

// ── Duration 기반 역방향 명령 스케줄링 ──
actionsToExecute.forEach(function(action) {
    if (action.duration > 0) {
        var reverseCmd = REVERSE_CMD[action.command];
        if (!reverseCmd) return;

        var timerKey = 'dur_' + action.deviceId;
        var existingTimer = context.get(timerKey);
        if (existingTimer) clearTimeout(existingTimer);

        var timer = setTimeout(function() {
            var reverseMsg = {
                control: {
                    houseId: action.houseId,
                    deviceId: action.deviceId,
                    deviceType: action.deviceType,
                    command: reverseCmd,
                    operator: 'automation_duration',
                    requestId: 'auto_dur_' + Date.now(),
                    timestamp: new Date().toISOString()
                }
            };
            var logMsg = {
                topic: 'INSERT INTO control_logs (timestamp, device_id, command, source, synced) VALUES ($1, $2, $3, $4, 0)',
                payload: [new Date().toISOString(), action.deviceId, reverseCmd, 'automation_duration']
            };
            node.send([[reverseMsg], null, [logMsg]]);
            node.warn('⏱️ Duration 종료: ' + action.deviceId + ' → ' + reverseCmd);
            context.set(timerKey, null);
            var reg2 = context.get('timerRegistry') || {};
            delete reg2[timerKey];
            context.set('timerRegistry', reg2);
        }, action.duration * 1000);

        context.set(timerKey, timer);
        var reg = context.get('timerRegistry') || {};
        reg[timerKey] = action.ruleId;
        context.set('timerRegistry', reg);
        node.warn('⏱️ Duration 설정: ' + action.deviceId + ' ' + action.duration + '초 후 → ' + reverseCmd);
    }
});

var logMessages = actionsToExecute.map(function(action) {
    return {
        topic: 'INSERT INTO control_logs (timestamp, device_id, command, source, synced) VALUES ($1, $2, $3, $4, 0)',
        payload: [now.toISOString(), action.deviceId, action.command, 'automation']
    };
});

return [controlMessages.length > 0 ? [controlMessages] : null, updateMessages.length > 0 ? [updateMessages] : null, logMessages.length > 0 ? [logMessages] : null];

